package com.socialblog.comment.application;import com.fasterxml.jackson.databind.*;import com.socialblog.comment.domain.*;import com.socialblog.comment.repository.*;import io.micrometer.core.instrument.Metrics;import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;import org.springframework.kafka.annotation.KafkaListener;import org.springframework.stereotype.Component;import org.springframework.transaction.annotation.Transactional;import java.util.UUID;
@Component @ConditionalOnProperty(name="app.kafka.consumer-enabled",havingValue="true",matchIfMissing=true)public class ArticleEventConsumer{private final ObjectMapper json;private final ArticleProjectionRepository articles;private final ProcessedEventRepository processed;public ArticleEventConsumer(ObjectMapper j,ArticleProjectionRepository a,ProcessedEventRepository p){json=j;articles=a;processed=p;}@KafkaListener(topics="articles.events")@Transactional public void consume(String raw)throws Exception{JsonNode e=json.readTree(raw);UUID eventId=UUID.fromString(e.path("eventId").asText());if(processed.existsById(eventId))return;String type=e.path("eventType").asText();JsonNode payload=e.path("payload");UUID articleId=UUID.fromString(payload.path("articleId").asText());if(type.equals("ArticlePublished")||type.equals("ArticleDeleted")){UUID author=payload.hasNonNull("authorId")?UUID.fromString(payload.path("authorId").asText()):null;ArticleProjection a=articles.findById(articleId).orElseGet(()->new ArticleProjection(articleId,false,author));a.update(type.equals("ArticlePublished"),author);articles.save(a);processed.save(new ProcessedEvent(eventId,type));Metrics.counter("socialblog.kafka.consumer.events","topic","articles.events","eventType",type,"outcome","processed").increment();}}}
